-- Create "obs_alert_rules" table
CREATE TABLE "obs_alert_rules" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "metric_type" character varying NOT NULL DEFAULT 'error_rate',
  "operator" character varying NOT NULL DEFAULT 'gt',
  "threshold" double precision NOT NULL,
  "severity" character varying NOT NULL DEFAULT 'warning',
  "enabled" boolean NOT NULL DEFAULT true,
  "window_seconds" bigint NOT NULL DEFAULT 3600,
  "cooldown_seconds" bigint NOT NULL DEFAULT 0,
  "min_request_count" bigint NOT NULL DEFAULT 0,
  "scope_json" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "obsalertrule_enabled_metric_type" to table: "obs_alert_rules"
CREATE INDEX "obsalertrule_enabled_metric_type" ON "obs_alert_rules" ("enabled", "metric_type");
-- Create index "obsalertrule_name" to table: "obs_alert_rules"
CREATE UNIQUE INDEX "obsalertrule_name" ON "obs_alert_rules" ("name");
-- Create index "obsalertrule_severity_enabled" to table: "obs_alert_rules"
CREATE INDEX "obsalertrule_severity_enabled" ON "obs_alert_rules" ("severity", "enabled");
-- Create "obs_alert_silences" table
CREATE TABLE "obs_alert_silences" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "comment" character varying NULL,
  "matcher_json" jsonb NULL,
  "starts_at" timestamptz NOT NULL,
  "ends_at" timestamptz NOT NULL,
  "created_by" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "obsalertsilence_starts_at_ends_at" to table: "obs_alert_silences"
CREATE INDEX "obsalertsilence_starts_at_ends_at" ON "obs_alert_silences" ("starts_at", "ends_at");
-- Create "scheduled_test_plan_runs" table
CREATE TABLE "scheduled_test_plan_runs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "plan_id" bigint NOT NULL,
  "trigger" character varying NOT NULL DEFAULT 'schedule',
  "status" character varying NOT NULL DEFAULT 'ok',
  "selected" bigint NOT NULL DEFAULT 0,
  "probed" bigint NOT NULL DEFAULT 0,
  "skipped" bigint NOT NULL DEFAULT 0,
  "failed" bigint NOT NULL DEFAULT 0,
  "unhealthy" bigint NOT NULL DEFAULT 0,
  "recovered" bigint NOT NULL DEFAULT 0,
  "summary" character varying NOT NULL DEFAULT '',
  "started_at" timestamptz NOT NULL,
  "finished_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "scheduledtestplanrun_plan_id_started_at" to table: "scheduled_test_plan_runs"
CREATE INDEX "scheduledtestplanrun_plan_id_started_at" ON "scheduled_test_plan_runs" ("plan_id", "started_at");
-- Create "scheduled_test_plans" table
CREATE TABLE "scheduled_test_plans" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "scope_type" character varying NOT NULL DEFAULT 'all',
  "scope_id" bigint NULL,
  "interval_seconds" bigint NOT NULL DEFAULT 3600,
  "cron_expression" character varying NULL,
  "max_results" bigint NOT NULL DEFAULT 0,
  "auto_recover" boolean NOT NULL DEFAULT false,
  "last_run_at" timestamptz NULL,
  "last_status" character varying NOT NULL DEFAULT '',
  "last_summary" character varying NOT NULL DEFAULT '',
  PRIMARY KEY ("id")
);
-- Create index "scheduledtestplan_enabled" to table: "scheduled_test_plans"
CREATE INDEX "scheduledtestplan_enabled" ON "scheduled_test_plans" ("enabled");
-- Create index "scheduledtestplan_scope_type_scope_id" to table: "scheduled_test_plans"
CREATE INDEX "scheduledtestplan_scope_type_scope_id" ON "scheduled_test_plans" ("scope_type", "scope_id");
